95: 			}
96: 		} else {
97: 			// Nothing known was set. This must be some future, unknown extension,
98: 			// so we don't know how to handle it. We may still be able to allocated from
99: 			// other pools, so we continue.
100: 			//
101: 			// TODO (eventually): let caller decide how to report this to the user. Warning
102: 			// about it for every slice on each scheduling attempt would be too noisy, but
103: 			// perhaps once per run would be useful?
104: 			continue
105: 		}
106: 
107: 	}
108: 
109: 	// Find incomplete pools and flatten into a single slice.
110: 	//
111: 	// When we get here, we only have slices relevant for the node.
112: 	// There is at least one.
113: 	// We may have skipped slices with a higher generation
114: 	// if they are not relevant for the node, so we have to be
115: 	// careful with the "is incomplete" check.
116: 	result := make([]*Pool, 0, len(pools))
117: 	for poolID, slicesForPool := range pools {
118: 		// If we have all slices, we are done.
119: 		isComplete := int64(len(slicesForPool)) == slicesForPool[0].Spec.Pool.ResourceSliceCount
120: 		if isComplete {
121: 			pool, err := buildPool(poolID, slicesForPool, features, nil)
122: 			if err != nil {
123: 				return nil, err
124: 			}
125: 			result = append(result, pool)
126: 			continue
127: 		}
128: 		// If not, then we need to start looking for slices
129: 		// which were filtered out above because their node selection made them look irrelevant
130: 		// for the current node. This is necessary for "allocate all" mode (it rejects incomplete
131: 		// pools).
132: 		isObsolete, allSlicesForPool := checkSlicesInPool(slices, poolID, slicesForPool[0].Spec.Pool.Generation)
133: 		if isObsolete {
134: 			// A more thorough check determined that the DRA driver is in the process
135: 			// of replacing the current generation. The newer one didn't have any slice
136: 			// which devices for the node, or we would have noticed sooner.
137: 			//
138: 			// Let's ignore the old device information by ignoring the pool.
139: 			continue
140: 		}
141: 		// Use the more complete number of slices to check for "incomplete pool".
142: 		//
143: 		// The slices that we return to the caller still don't represent the whole
144: 		// pool, but that's okay: we *want* to limit the result to relevant devices
145: 		// so the caller doesn't need to check node selectors unnecessarily.
146: 		isComplete = int64(len(allSlicesForPool)) == slicesForPool[0].Spec.Pool.ResourceSliceCount
147: 		// If a pool is incomplete, we don't allow allocation so we don't need
148: 		// to do any validation. We need to keep track of the incomplete pools here
149: 		// to make sure allocationMode: All doesn't succeed without considering all
150: 		// devices.
151: 		if !isComplete {
152: 			result = append(result, &Pool{
153: 				PoolID:       poolID,
154: 				IsIncomplete: true,
155: 			})
156: 			continue
157: 		}
158: 		pool, err := buildPool(poolID, slicesForPool, features, allSlicesForPool)
159: 		if err != nil {
160: 			return nil, err
161: 		}
162: 		result = append(result, pool)
163: 	}
164: 
165: 	return result, nil
166: }
