199: func buildPool(id PoolID, slices []*draapi.ResourceSlice, features Features, allSlicesForPool []*resourceapi.ResourceSlice) (*Pool, error) {
200: 	var deviceSlices []*draapi.ResourceSlice
201: 	var counterSetSlices []*draapi.ResourceSlice
202: 	if features.PartitionableDevices {
203: 		for _, slice := range slices {
204: 			if len(slice.Spec.SharedCounters) > 0 {
205: 				counterSetSlices = append(counterSetSlices, slice)
206: 			} else {
207: 				deviceSlices = append(deviceSlices, slice)
208: 			}
209: 		}
210: 	} else {
211: 		deviceSlices = slices
212: 	}
213: 	if err := validateDeviceNames(deviceSlices); err != nil {
214: 		return &Pool{
215: 			PoolID:        id,
216: 			IsInvalid:     true,
217: 			InvalidReason: err.Error(),
218: 		}, nil
219: 	}
220: 	// If the partitionable devices feature is not enabled, we don't need to
221: 	// validate counter sets and consumed counters, so we are done.
222: 	if !features.PartitionableDevices {
223: 		return &Pool{
224: 			PoolID:                    id,
225: 			DeviceSlicesTargetingNode: deviceSlices,
226: 		}, nil
227: 	}
228: 
229: 	counterSets, err := getAndValidateCounterSets(counterSetSlices)
230: 	if err != nil {
231: 		return &Pool{
232: 			PoolID:        id,
233: 			IsInvalid:     true,
234: 			InvalidReason: err.Error(),
235: 		}, nil
236: 	}
237: 
238: 	if err := validateDeviceCounterConsumption(counterSets, slices); err != nil {
239: 		return &Pool{
240: 			PoolID:        id,
241: 			IsInvalid:     true,
242: 			InvalidReason: err.Error(),
243: 		}, nil
244: 	}
245: 	// If we have already seen all slices (both with counter sets and devices),
246: 	// we don't need to do any more validation.
247: 	if allSlicesForPool == nil || len(slices) == len(allSlicesForPool) {
248: 		return &Pool{
249: 			PoolID:                    id,
250: 			DeviceSlicesTargetingNode: deviceSlices,
251: 			CounterSets:               counterSets,
252: 		}, nil
253: 	}
254: 
255: 	// If we have slices that were discarded earlier because they didn't target the current node
256: 	// we need to check them now. They might include devices that consume counters in the pool and
257: 	// the allocator needs to know about them to correctly determine available counters.
258: 	//
259: 	// We only want to convert the slices we haven't already converted, so make it easy to
260: 	// look up the names of converted slices.
261: 	slicesTargetingNodeNames := sets.New[string]()
262: 	for _, slice := range slices {
263: 		slicesTargetingNodeNames.Insert(slice.Name)
264: 	}
265: 	var slicesNotTargetingNode []*draapi.ResourceSlice
266: 	for _, slice := range allSlicesForPool {
267: 		if slicesTargetingNodeNames.Has(slice.Name) {
268: 			continue
269: 		}
270: 		var convertedSlice draapi.ResourceSlice
271: 		if err := draapi.Convert_v1_ResourceSlice_To_api_ResourceSlice(slice, &convertedSlice, nil); err != nil {
272: 			return nil, fmt.Errorf("convert ResourceSlice: %w", err)
273: 		}
274: 		slicesNotTargetingNode = append(slicesNotTargetingNode, &convertedSlice)
275: 	}
276: 	// We need to make sure the devices here are correctly consuming counters and counter
277: 	// sets. Otherwise the allocator might make incorrect decisions.
278: 	// We don't validate the device names here. It might be that we should do that, but
279: 	// this is consistent with existing behavior where we don't validate slices that
280: 	// we don't allocate from.
281: 	if err := validateDeviceCounterConsumption(counterSets, slicesNotTargetingNode); err != nil {
282: 		return &Pool{
283: 			PoolID:        id,
284: 			IsInvalid:     true,
285: 			InvalidReason: err.Error(),
286: 		}, nil
287: 	}
288: 	return &Pool{
289: 		PoolID:                       id,
290: 		DeviceSlicesTargetingNode:    deviceSlices,
291: 		DeviceSlicesNotTargetingNode: slicesNotTargetingNode,
292: 		CounterSets:                  counterSets,
293: 	}, nil
294: }
