296: func getAndValidateCounterSets(slices []*draapi.ResourceSlice) (map[draapi.UniqueString]*draapi.CounterSet, error) {
297: 	counterSets := make(map[draapi.UniqueString]*draapi.CounterSet)
298: 	// We only capture the first error we encounter.
299: 	for _, slice := range slices {
300: 		for i := range slice.Spec.SharedCounters {
301: 			counterSet := slice.Spec.SharedCounters[i]
302: 			if _, found := counterSets[counterSet.Name]; found {
303: 				return nil, fmt.Errorf("duplicate counter set name %s", counterSet.Name)
304: 			}
305: 			counterSets[counterSet.Name] = &counterSet
306: 		}
307: 	}
308: 	return counterSets, nil
309: }
