311: func validateDeviceNames(resourceSlices []*draapi.ResourceSlice) error {
312: 	deviceNames := sets.New[draapi.UniqueString]()
313: 	for _, slice := range resourceSlices {
314: 		for _, device := range slice.Spec.Devices {
315: 			// Make sure we don't have duplicate device names
316: 			if deviceNames.Has(device.Name) {
317: 				return fmt.Errorf("duplicate device name %s", device.Name)
318: 			}
319: 			deviceNames.Insert(device.Name)
320: 		}
321: 	}
322: 	return nil
323: }
