325: func validateDeviceCounterConsumption(counterSets map[draapi.UniqueString]*draapi.CounterSet, resourceSlices []*draapi.ResourceSlice) error {
326: 	for _, slice := range resourceSlices {
327: 		for _, device := range slice.Spec.Devices {
328: 			// Make sure all consumed counters for the device references counter sets that exists and
329: 			// that they consume counters that exists within those counter sets.
330: 			for _, deviceCounterConsumption := range device.ConsumesCounters {
331: 				counterSet, found := counterSets[deviceCounterConsumption.CounterSet]
332: 				if !found {
333: 					return fmt.Errorf("counter set %s not found", deviceCounterConsumption.CounterSet)
334: 				}
335: 
336: 				for counterName := range deviceCounterConsumption.Counters {
337: 					if _, found := counterSet.Counters[counterName]; !found {
338: 						return fmt.Errorf("counter %s not found in counter set %s", counterName, counterSet.Name)
339: 					}
340: 				}
341: 			}
342: 		}
343: 	}
344: 	return nil
345: }
