347: // checkSlicesInPool is an expensive check of all slices in the pool.
348: // The generation is what the caller wants to move ahead with.
349: //
350: // It returns:
351: // - current generation is obsolete -> no further checking
352: // - all slices with the generation in the pool
353: //
354: // Future TODO: detect inconsistent ResourceSliceCount, also in poolIsInvalid.
355: func checkSlicesInPool(slices []*resourceapi.ResourceSlice, poolID PoolID, generation int64) (bool, []*resourceapi.ResourceSlice) {
356: 	// A cached index by pool ID would make this more efficient.
357: 	// It may be needed long-term to support features which always have to consider all slices.
358: 	var allSlicesForPool []*resourceapi.ResourceSlice
359: 	for i := range slices {
360: 		slice := slices[i]
361: 		if slice.Spec.Driver != poolID.Driver.String() ||
362: 			slice.Spec.Pool.Name != poolID.Pool.String() {
363: 			// Different pool.
364: 			continue
365: 		}
366: 		switch {
367: 		case slice.Spec.Pool.Generation == generation:
368: 			allSlicesForPool = append(allSlicesForPool, slice)
369: 		case slice.Spec.Pool.Generation > generation:
370: 			// The caller must have missed some other slice in the pool.
371: 			// Abort!
372: 			return true, nil
373: 		default:
374: 			// Older generation, ignore.
375: 		}
376: 	}
377: 	return false, allSlicesForPool
378: }
