631: func (pl *DynamicResources) Filter(ctx context.Context, cs fwk.CycleState, pod *v1.Pod, nodeInfo fwk.NodeInfo) *fwk.Status {
632: 	if !pl.enabled {
633: 		return nil
634: 	}
635: 	state, err := getStateData(cs)
636: 	if err != nil {
637: 		return statusError(klog.FromContext(ctx), err)
638: 	}
639: 	if state.claims.empty() {
640: 		return nil
641: 	}
642: 
643: 	logger := klog.FromContext(ctx)
644: 	node := nodeInfo.Node()
645: 	nodeExtendedResourceClaim, containerResourceRequestMappings, status := pl.filterExtendedResources(state, pod, nodeInfo, logger)
646: 	if status != nil {
647: 		return status
648: 	}
649: 	// The pod has no user claim, it may have extended resource claim that is satisfied by device plugin.
650: 	// Then there is nothing left to do for this plugin.
651: 	if nodeExtendedResourceClaim == nil && state.claims.noUserClaim() {
652: 		return nil
653: 	}
654: 
655: 	var unavailableClaims []int
656: 	for index, claim := range state.claims.all() {
657: 		logger.V(10).Info("filtering based on resource claims of the pod", "pod", klog.KObj(pod), "node", klog.KObj(node), "resourceclaim", klog.KObj(claim))
658: 
659: 		// This node selector only gets set if the claim is allocated.
660: 		if nodeSelector := state.informationsForClaim[index].availableOnNodes; nodeSelector != nil && !nodeSelector.Match(node) {
661: 			logger.V(5).Info("allocation's node selector does not match", "pod", klog.KObj(pod), "node", klog.KObj(node), "resourceclaim", klog.KObj(claim))
662: 			unavailableClaims = append(unavailableClaims, index)
663: 			continue
664: 		}
665: 
666: 		if claim.Status.Allocation == nil {
667: 			// The claim is not allocated yet, don't have to check
668: 			// anything else.
669: 			continue
670: 		}
671: 
672: 		// The claim is allocated, check whether it is ready for binding.
673: 		if pl.fts.EnableDRADeviceBindingConditions && pl.fts.EnableDRAResourceClaimDeviceStatus {
674: 			ready, err := pl.isClaimReadyForBinding(claim)
675: 			// If the claim is not ready yet (ready false, no error) and binding has timed out
676: 			// or binding has failed (err non-nil), then the scheduler should consider deallocating this
